571→                                        <path fillRule="evenodd" clipRule="evenodd" d="M8 1.25C5.37665 1.25 3.25 3.37665 3.25 6V20.4648C3.25 21.7269 4.27311 22.75 5.53518 22.75C5.98634 22.75 6.42739 22.6165 6.80278 22.3662L11.3066 19.3636C11.7265 19.0837 12.2735 19.0837 12.6934 19.3636L17.1972 22.3662C17.5726 22.6165 18.0137 22.75 18.4648 22.75C19.7269 22.75 20.75 21.7269 20.75 20.4648V6C20.75 3.37665 18.6234 1.25 16 1.25H8ZM9 6.75C8.58579 6.75 8.25 7.08579 8.25 7.5C8.25 7.91421 8.58579 8.25 9 8.25H15C15.4142 8.25 15.75 7.91421 15.75 7.5C15.75 7.08579 15.4142 6.75 15 6.75H9Z" fill={isBookmarked ? "rgb(72, 208, 135)" : "var(--icon-default)"} />
572→                                    </svg>
573→                                    <span>{formatCounts(bookmarkCounts)}</span>
574→                                </button>
575→
576→                                {postData?.userId !== user?.userData?.[0]?.id && (
577→                                    <button
578→                                        className="cv-action-btn cv-action-btn--end"
579→                                        onClick={(e) => {
580→                                            e.stopPropagation();
581→                                            if(!session) return openAuthModal?.();
582→                                            setShowRepostModal(true);
583→                                        }}
584→                                    >
585→                                        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="var(--icon-default)">
586→                                            <path d="M7 7h10l-1.293-1.293a1 1 0 0 1 1.414-1.414l3 3a1 1 0 0 1 0 1.414l-3 3a1 1 0 0 1-1.414-1.414L17 9H7a1 1 0 0 1-1-1V5a1 1 0 0 1 2 0v2zm10 10H7l1.293 1.293a1 1 0 0 1-1.414 1.414l-3-3a1 1 0 0 1 0-1.414l3-3a1 1 0 1 1 1.414 1.414L7 15h10a1 1 0 0 1 1 1v3a1 1 0 0 1-2 0v-2z"/>
587→                                        </svg>
588→                                        <span>Repost</span>
589→                                    </button>
590→                                )}
591→
592→                                <div style={{ position: 'relative', marginLeft: postData?.userId === user?.userData?.[0]?.id ? 'auto' : '0' }}>
593→                                    <button
594→                                        className="cv-action-btn"
595→                                        onClick={(e) => { e.stopPropagation(); setShowShareMenu((v) => !v); }}
596→                                    >
597→                                        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="var(--icon-default)">
598→                                            <path d="M18 16.08c-.76 0-1.44.3-1.96.77L8.91 12.7c.05-.23.09-.46.09-.7s-.04-.47-.09-.7l7.05-4.11c.54.5 1.25.81 2.04.81 1.66 0 3-1.34 3-3s-1.34-3-3-3-3 1.34-3 3c0 .24.04.47.09.7L8.04 9.81C7.5 9.31 6.79 9 6 9c-1.66 0-3 1.34-3 3s1.34 3 3 3c.79 0 1.5-.31 2.04-.81l7.12 4.16c-.05.21-.08.43-.08.65 0 1.61 1.31 2.92 2.92 2.92 1.61 0 2.92-1.31 2.92-2.92s-1.31-2.92-2.92-2.92z"/>
599→                                        </svg>
600→                                    </button>
601→                                    {showShareMenu && (
602→                                        <ShareMenu
603→                                            url={getShareUrl(postData?.journalId)}
604→                                            title={postData?.title || ''}
605→                                            onClose={() => setShowShareMenu(false)}
606→                                        />
607→                                    )}
608→                                </div>
609→                            </div>
610→
611→                            <div className="cv-body">
612→                                <LexicalComposer initialConfig={{
613→                                    namespace: "ContentViewer",
614→                                    theme: theme,
615→                                    editable: false,
616→                                    editorState: postData?.content,
617→                                    nodes: [HeadingNode, ImageNode, QuoteNode],
618→                                    onError(error) { throw error; },
619→                                }}>
620→                                    <RichTextPlugin
621→                                        contentEditable={<ContentEditable />}
622→                                        ErrorBoundary={LexicalErrorBoundary}
623→                                    />
624→                                </LexicalComposer>
625→                            </div>
626→                        </>
627→                    )}
628→                </article>
629→
630→                <RelatedPosts journalId={postData?.journalId} />
631→
632→                {/* Toast notification */}
633→            <AnimatePresence>
634→                {(bookmarkedMessage) && (
635→                    <motion.div
636→                        className="cv-toast"
637→                        initial={{ opacity: 0, y: 8 }}
638→                        animate={{ opacity: 1, y: 0 }}
639→                        exit={{ opacity: 0, y: 8 }}
640→                        transition={{ duration: 0.2, ease: "easeOut" }}
641→                    >
642→                        {bookmarkedMessage}
643→                    </motion.div>
644→                )}
645→            </AnimatePresence>
646→            </div>
647→
648→            {showRepostModal && postData && (
649→                <RepostModal
650→                    journal={{
651→                        id: postData.journalId,
652→                        title: postData.title,
653→                        users: {
654→                            id: postData.userId,
655→                            name: postData.name,
656→                            image_url: postData.avatar,
657→                            badge: postData.badge
658→                        }
659→                    }}
660→                    onClose={(result) => {
661→                        setShowRepostModal(false);
662→                        if(result === 'success'){
663→                            setBookmarkedMessage('Post was reposted');
664→                            if(timeOutRefBookmark.current){
665→                                clearTimeout(timeOutRefBookmark.current);
666→                            }
667→                            timeOutRefBookmark.current = setTimeout(() => {
668→                                setBookmarkedMessage('');
669→                            }, 2500);
670→                        }
671→                    }}
672→                />
673→            )}
674→        </>
675→    )
676→}
677→
678→export default ContentView;
